// src/pages/Home/index.jsx (VERSÃO CORRIGIDA)

import Header from '../../components/layout/Header/Header';
import Footer from '../../components/layout/Footer/Footer';
import ServiceCard from '../../components/services/ServiceCard';

// Usando o "barril" de dados, o caminho também precisa ser corrigido
import * as serviceData from '../../data';

// O resto do seu componente continua igual
const Home = () => {
  return (
    <>
      <Header />
      <main className="page-container">
        <div className="container">
          <div className="service-grid">
            
            <h2 className="grid-section-title">Limpeza e Manutenção</h2>
            {serviceData.cleaningServices.map((service) => (
              <ServiceCard key={service.title} {...service} />
            ))}

            {/* ... e assim por diante para as outras categorias ... */}
            
          </div>
        </div>
      </main>
      <Footer />
    </>
  );
};

export default Home;
